class Solution: def gcd(self, a: int, b: int) -> int: if b == 0: return a; else: return self.gcd(b, a % b)

if __name__ == '__main__':
    s = Solution()
    a, b = map(int, input().split())
    print(s.gcd(a, b))

solutions.cpp:
class Solution { public: int gcd(int a, int b) { if (b == 0) return a; else return gcd(b, a % b); } };

int main() {
    Solution s;
    int a, b;
    std::cin >> a >> b;
    std::cout << s.gcd(a, b) << std::endl;
    return 0;
}
